    // Endpoint: upload original PDF, convert to HTML and return HTML content
    // Endpoint: upload original PDF, convert to HTML and return HTML content
    public function convertUpload(Request $request)
    {
        $request->validate([
            'pdf' => 'required|file|mimes:pdf|max:51200' // 50MB
        ]);

        $file = $request->file('pdf');

        if (!$file->isValid()) {
            return response()->json([
                'success' => false,
                'message' => 'Uploaded file is invalid',
            ], 400);
        }
        $originalName = $file->getClientOriginalName();
        $path = $file->store('uploads/originals'); // storage/app/uploads/originals/
        $absStoragePath = storage_path('app/' . $path);


        $uploadFolder = storage_path('app/uploads/originals');
        if (!is_dir($uploadFolder)) {
            mkdir($uploadFolder, 0755, true);
        }

        // Save the file manually
        $originalName = Str::random(16) . '.' . $file->getClientOriginalExtension();
        $absStoragePath = $uploadFolder . '/' . $originalName;

        $file->move($uploadFolder, $originalName);

        // Verify file exists
        if (!file_exists($absStoragePath)) {
            return response()->json([
                'success' => false,
                'message' => 'File could not be saved. Path: ' . $absStoragePath
            ], 500);
        }


        try {
            $token = '71DCEqx1YhOnHDyEKkXfy7ADLKow6f9o';
            $response = Http::withHeaders([
                'Authorization' => 'Bearer ' . $token,
            ])->attach(
                'File',
                file_get_contents($absStoragePath),
                $originalName
            )->withOptions([
                'verify' => false,
            ])->post('https://v2.convertapi.com/convert/pdf/to/html', [
                'StoreFile' => 'true',
                'FixedElements' => 'relative',
            ]);

            if ($response->failed()) {
                return response()->json([
                    'success' => false,
                    'message' => 'Conversion failed: ' . $response->body(),
                ], 500);
            }

            $htmlUrl = $response->json()['Files'][0]['Url'];
        } catch (\Exception $e) {
            return response()->json([
                'success' => false,
                'message' => 'Conversion failed: ' . $e->getMessage()
            ], 500);
        }

         $htmlContent = '';
        try {
            $htmlContent = Http::withOptions(['verify' => false])->get($htmlUrl)->body();
        } catch (\Exception $e) {
            Log::warning('Could not fetch HTML preview: ' . $e->getMessage());
        }

        // $htmlUrl = "https://v2.convertapi.com/d/gc0h8a3hsk8dtwawiv9bbg41e42o03ud/KV9iOGKjm8YSb6xE.html";

        return response()->json([
            'success' => true,
            'html' =>  $htmlContent,
            'htmlUrl' => $htmlUrl,
            'original_name' => $originalName,
            'stored_path' => $absStoragePath
        ]);
    }

