    // Delete
    public function destroy(PdfDocument $pdf)
    {
        // Delete files if exist
        if ($pdf->pdf_path) {
            Storage::delete($pdf->pdf_path);
        }
        if ($pdf->original_pdf_path) {
            Storage::delete($pdf->original_pdf_path);
        }
        $pdf->delete();
        return back()->with('success', 'Deleted');
    }

    public function pushToRemote(Request $request, PdfDocument $pdf)
{
    // Ensure file exists locally
    if (empty($pdf->pdf_path)) {
        return back()->with('error', 'No local PDF file saved for this record.');
    }

    // Convert 'public/pdfs/name.pdf' -> 'pdfs/name.pdf' path to storage path
    $localPath = storage_path('app/' . $pdf->pdf_path);

    if (!file_exists($localPath)) {
        return back()->with('error', "Local file not found: {$localPath}");
    }

    $remoteUrl = config('services.pdf_push.url');
    $token = config('services.pdf_push.token');

    if (empty($remoteUrl) || empty($token)) {
        return back()->with('error', 'Remote push URL or token is not configured in .env');
    }

    try {
        $response = Http::withHeaders([
            'X-PUSH-TOKEN' => $token,
        ])
        ->withoutVerifying()
        ->timeout(320) 
        ->attach(
            'file',
            fopen($localPath, 'r'),
            basename($localPath)
        )->post($remoteUrl, [
            'id' => $pdf->id,
            'name' => $pdf->name,
            'slug' => $pdf->slug,
        ]);

        if ($response->successful()) {
            $json = $response->json();
            // mark local record as pushed
            $pdf->update([
                'is_pushed' => true,
                'pushed_at' => now(),
            ]);

            return back()->with('success', $json['message'] ?? 'Pushed successfully')
                         ->with('download_url', $json['download_url'] ?? null);
        } else {
            // optional: mark as not pushed
            $pdf->update([
                'is_pushed' => false,
                'pushed_at' => null,
            ]);
            dd($response->body());
            return back()->with('error', 'Push failed: ' . $response->body());
        }
    } catch (\Exception $e) {
        // optional: mark as not pushed
        $pdf->update([
            'is_pushed' => false,
            'pushed_at' => null,
        ]);

        dd($e->getMessage());
        return back()->with('error', 'Push exception: ' . $e->getMessage());
    }
}

public function receiveRemotePush(Request $request)
{
    Log::info('receiveRemotePush called', ['ip' => $request->ip(), 'all' => $request->all()]);

    // Validate token header
    $token = $request->header('X-PUSH-TOKEN');
    if ($token !== config('services.pdf_push.token')) {
        return response()->json(['success' => false, 'message' => 'Unauthorized'], 401);
    }

    $request->validate([
        'file' => 'required|file|mimes:pdf|max:51200',
        'name' => 'nullable|string|max:255',
        'slug' => 'nullable|string|max:255',
        'id' => 'nullable|integer'
    ]);

    $file = $request->file('file');
    $name = $request->input('name') ?? pathinfo($file->getClientOriginalName(), PATHINFO_FILENAME);
    $slug = $request->input('slug') ?? Str::slug($name);
    $pdfFolder = 'pdfs';
    $disk = Storage::disk('public');

    // Build filename and backup existing
    $filename = $slug . '.pdf';
    if ($disk->exists("{$pdfFolder}/{$filename}")) {
        $timestamp = Carbon::now()->format('YmdHis');
        $backupName = Str::replaceLast('.pdf', "-{$timestamp}.pdf", $filename);
        $disk->move("{$pdfFolder}/{$filename}", "{$pdfFolder}/backups/{$backupName}");
    }

    // Save new file
    $path = $disk->putFileAs($pdfFolder, $file, $filename); // returns path like 'pdfs/slug.pdf'

    // Update or create DB record
    $pdfDoc = null;
    if ($request->has('id')) {
        $pdfDoc = \App\Models\PdfDocument::find($request->input('id'));
    }
    if (!$pdfDoc) {
        $pdfDoc = \App\Models\PdfDocument::where('slug', $slug)->first();
    }
    $values = [
        'name' => $name,
        'slug' => $slug,
        'pdf_path' => 'public/' . $path,
        'original_filename' => $file->getClientOriginalName(),
        'mime' => $file->getMimeType(),
        'size' => $file->getSize(),
    ];
    if ($pdfDoc) {
        $pdfDoc->update($values);
    } else {
        $values['created_by'] = null;
        $pdfDoc = \App\Models\PdfDocument::create($values);
    }

    $downloadUrl = asset('storage/' . $path); // public URL (requires php artisan storage:link)

    return response()->json([
        'success' => true,
        'message' => 'File saved on server',
        'id' => $pdfDoc->id,
        'download_url' => $downloadUrl,
        'path' => $path,
    ]);
}


public function storageIndex()
{
    $disk = Storage::disk('public');
    $files = $disk->files('pdfs'); // returns array like ['pdfs/file.pdf', 'pdfs/backups/...']

    // Optionally filter out backups folder
    $files = array_filter($files, fn($f) => !Str::startsWith($f, 'pdfs/backups/'));

    // Build an array of items with url and name
    $items = array_map(function($f) use ($disk) {
        return [
            'path' => $f,
            'filename' => basename($f),
            'url' => asset('storage/' . $f),
            'size' => $disk->size($f),
            'modified' => date('Y-m-d H:i:s', $disk->lastModified($f))
        ];
    }, $files);

    return view('pdfs.storage_index', ['items' => $items]);
}

public function storageView($filename)
{
    // sanitize filename (no slashes)
    if (Str::contains($filename, ['..','/','\\'])) abort(400);
    $path = storage_path('app/public/pdfs/' . $filename);
    if (!file_exists($path)) abort(404);
    return response()->file($path, ['Content-Type' => 'application/pdf']);
}




