public function update(Request $request, PdfDocument $pdf)
{
    $request->validate([
        'name' => 'required|string|max:255',
        'html' => 'required|string',
    ]);

    $name = $request->input('name');
    $html = $request->input('html');

    $slug = $pdf->slug; // KEEP SAME SLUG

    // Save temp HTML
    $tmpHtmlPath = storage_path('app/uploads/html_' . Str::random(8) . '.html');
    file_put_contents($tmpHtmlPath, $html);

    $pdfFileName = "pdfs/{$slug}.pdf";
    $pdfAbsolute = storage_path('app/public/' . $pdfFileName);

    try {

        $chromePath = "C:\\Users\\admin\\AppData\\Local\\Google\\Chrome\\Application\\chrome.exe";
        $nodePath = "C:\\Program Files\\nodejs\\node.exe";

        Browsershot::html(file_get_contents($tmpHtmlPath))
            ->margins(10, 10, 10, 10)
            ->showBackground()
            ->format('A4')
            ->noSandbox()
            ->setChromePath($chromePath)
            ->setNodeBinary($nodePath)
            ->save($pdfAbsolute);

    } catch (\Exception $e) {
        return response()->json([
            'success' => false,
            'message' => 'PDF regeneration failed: ' . $e->getMessage()
        ], 500);
    } finally {
        @unlink($tmpHtmlPath);
    }

    // UPDATE DB + RESET PUSH STATUS
    $pdf->update([
        'name' => $name,
        'html' => $html,
        'size' => filesize($pdfAbsolute),
        'is_pushed' => false,      // VERY IMPORTANT
        'pushed_at' => null,       // VERY IMPORTANT
    ]);

    return response()->json([
        'success' => true,
        'message' => 'PDF updated successfully',
        'download_url' => asset('storage/pdfs/' . $slug . '.pdf')
    ]);
}


